import React, { createContext, useContext, useState, useEffect } from 'react';

const SubscriptionContext = createContext();

export const SubscriptionProvider = ({ children }) => {
  const [subscriptions, setSubscriptions] = useState([]);
  const [isScanning, setIsScanning] = useState(false);
  const [stats, setStats] = useState({
    totalMonthlySpend: 0,
    zombieSubscriptions: 0,
    potentialSavings: 0,
  });

  const mockSubscriptions = [
    { id: 1, name: 'Netflix', price: 649, lastUsed: '2 days ago', status: 'Active', category: 'OTT', icon: '🎬', zombieScore: 15 },
    { id: 2, name: 'Spotify', price: 119, lastUsed: '1 week ago', status: 'Active', category: 'Music', icon: '🎵', zombieScore: 25 },
    { id: 3, name: 'Adobe CC', price: 4230, lastUsed: '24 days ago', status: 'Zombie', category: 'SaaS', icon: '🎨', zombieScore: 88 },
    { id: 4, name: 'Canva Pro', price: 499, lastUsed: '3 days ago', status: 'Duplicate', category: 'Design', icon: '✨', zombieScore: 40 },
    { id: 5, name: 'Zeroify', price: 1599, lastUsed: '45 days ago', status: 'Zombie', category: 'Health', icon: '🧘', zombieScore: 92 },
    { id: 6, name: 'LinkedIn Premium', price: 1800, lastUsed: '12 days ago', status: 'Active', category: 'Social', icon: '💼', zombieScore: 35 },
    { id: 7, name: 'Amazon Prime', price: 1499, lastUsed: '2 months ago', status: 'Zombie', category: 'SaaS', icon: '📦', zombieScore: 85 },
    { id: 8, name: 'Hotstar', price: 299, lastUsed: '1 day ago', status: 'Active', category: 'OTT', icon: '🌟', zombieScore: 10 },
  ];

  const scanSubscriptions = async () => {
    setIsScanning(true);
    // Simulate scan delay
    await new Promise(resolve => setTimeout(resolve, 3000));

    setSubscriptions(mockSubscriptions);
    calculateStats(mockSubscriptions);
    setIsScanning(false);
  };

  const calculateStats = (subs) => {
    const total = subs.reduce((acc, sub) => acc + sub.price, 0);
    const zombies = subs.filter(sub => sub.status === 'Zombie').length;
    const savings = subs.filter(sub => sub.status === 'Zombie' || sub.status === 'Duplicate')
                        .reduce((acc, sub) => acc + sub.price, 0);

    setStats({
      totalMonthlySpend: total,
      zombieSubscriptions: zombies,
      potentialSavings: savings,
    });
  };

  const value = {
    subscriptions,
    isScanning,
    stats,
    scanSubscriptions,
  };

  return (
    <SubscriptionContext.Provider value={value}>
      {children}
    </SubscriptionContext.Provider>
  );
};

export const useSubscriptions = () => {
  const context = useContext(SubscriptionContext);
  if (!context) {
    throw new Error('useSubscriptions must be used within SubscriptionProvider');
  }
  return context;
};
